public string Humanize<T>(
    IEnumerable<T> collection, Func<T, object?> objectFormatter, string separator)
{
    ArgumentNullException.ThrowIfNull(collection);
    ArgumentNullException.ThrowIfNull(objectFormatter);

    // Single pass: compose the two transforms inline to avoid chained Select iterators.
    return HumanizeDisplayStrings(collection, item => objectFormatter(item)?.ToString(), separator);
}

/// <summary>
/// Formats and filters in a single pass over the source collection, avoiding
/// intermediate Select/Where/ToArray iterator chains.
/// </summary>
private string HumanizeDisplayStrings<T>(
    IEnumerable<T> source, Func<T, string?> formatter, string separator)
{
    var items = new List<string>();
    foreach (var element in source)
    {
        var formatted = formatter(element);
        if (formatted != null)
        {
            var trimmed = formatted.Trim();
            if (trimmed.Length > 0)
                items.Add(trimmed);
        }
    }

    if (items.Count == 0)
    {
        return string.Empty;
    }

    if (items.Count == 1)
    {
        return items[0];
    }

    var allButLast = string.Join(separator, items.Take(items.Count - 1));
    return $"{allButLast} and {items[^1]}";
}

