1. using System.Globalization;
2. 
3. namespace Textualizer;
4. 
5. /// <summary>
6. /// Specifies the unit of time for humanization purposes.
7. /// Values are ordered from largest to smallest.
8. /// </summary>
9. public enum TimeUnit
10. {
11.     /// <summary>Years.</summary>
12.     Year,
13.     /// <summary>Months.</summary>
14.     Month,
15.     /// <summary>Weeks.</summary>
16.     Week,
17.     /// <summary>Days.</summary>
18.     Day,
19.     /// <summary>Hours.</summary>
20.     Hour,
21.     /// <summary>Minutes.</summary>
22.     Minute,
23.     /// <summary>Seconds.</summary>
24.     Second,
25.     /// <summary>Milliseconds.</summary>
26.     Millisecond
27. }
28. 
29. /// <summary>
30. /// Provides extension methods for converting <see cref="TimeSpan"/> values to
31. /// human-readable strings with configurable precision, culture, and unit ranges.
32. /// </summary>
33. public static class TimeSpanReadabilityExtensions
34. {
35.     private const int DaysInAWeek = 7;
36.     private const double DaysInAYear = 365.2425;
37.     private const double DaysInAMonth = DaysInAYear / 12;
38. 
39.     // Reversed literal avoids Enumerable.Reverse + Enum.GetValues allocations at static init.
40.     private static readonly TimeUnit[] TimeUnits =
41.     [
42.         TimeUnit.Millisecond, TimeUnit.Second, TimeUnit.Minute, TimeUnit.Hour,
43.         TimeUnit.Day, TimeUnit.Week, TimeUnit.Month, TimeUnit.Year
44.     ];
45. 
46.     // Pre-computed lowercase unit names keyed by enum value, avoiding
47.     // Enum.ToString() (reflection-based) and ToLowerInvariant() per call.
48.     private static readonly string[] UnitNamesSingular;
49.     private static readonly string[] UnitNamesPlural;
50. 
51.     static TimeSpanReadabilityExtensions()
52.     {
53.         var values = Enum.GetValues<TimeUnit>();
54.         var max = 0;
55.         foreach (var v in values)
56.             if ((int)v > max)
57.                 max = (int)v;
58. 
59.         UnitNamesSingular = new string[max + 1];
60.         UnitNamesPlural = new string[max + 1];
61.         foreach (var v in values)
62.         {
63.             var name = v.ToString().ToLowerInvariant();
64.             UnitNamesSingular[(int)v] = name;
65.             UnitNamesPlural[(int)v] = name + "s";
66.         }
67.     }
68. 
69.     /// <summary>
70.     /// Converts a <see cref="TimeSpan"/> to a human-readable string.
71.     /// </summary>
72.     /// <param name="timeSpan">The time span to humanize.</param>
73.     /// <param name="precision">The number of time units to include (e.g., 2 for "1 hour, 30 minutes").</param>
74.     /// <param name="culture">The culture for localized formatting. Uses current culture if null.</param>
75.     /// <param name="maxUnit">The largest time unit to display.</param>
76.     /// <param name="minUnit">The smallest time unit to display.</param>
77.     /// <param name="collectionSeparator">The separator between time parts (default: ", ").</param>
78.     /// <param name="countEmptyUnits">Whether empty units count toward precision.</param>
79.     /// <returns>A human-readable string representation of the time span.</returns>
80.     /// <example>
81.     /// <code>
82.     /// TimeSpan.FromMinutes(90).Humanize() => "1 hour"
83.     /// TimeSpan.FromMinutes(90).Humanize(precision: 2) => "1 hour, 30 minutes"
84.     /// TimeSpan.FromDays(1.5).Humanize(precision: 3) => "1 day, 12 hours"
85.     /// </code>
86.     /// </example>
87.     public static string Humanize(
88.         this TimeSpan timeSpan,
89.         int precision = 1,
90.         CultureInfo? culture = null,
91.         TimeUnit maxUnit = TimeUnit.Year,
92.         TimeUnit minUnit = TimeUnit.Millisecond,
93.         string? collectionSeparator = null,
94.         bool countEmptyUnits = false)
95.     {
96.         culture ??= CultureInfo.CurrentCulture;
97. 
98.         // Use a stack-based buffer (max 8 units) to avoid List<> allocation.
99.         Span<string?> buffer = new string?[TimeUnits.Length];
100.         int count = CreateTimeParts(timeSpan, maxUnit, minUnit, buffer);
101. 
102.         if (IsContainingOnlyNullValue(buffer, count))
103.         {
104.             return "no time";
105.         }
106. 
107.         // Apply precision and collect non-null parts into a small list.
108.         Span<string> result = new string[Math.Min(precision, count)];
109.         int resultCount = ApplyPrecision(buffer, count, precision, countEmptyUnits, result);
110. 
111.         if (resultCount == 0)
112.         {
113.             return "no time";
114.         }
115. 
116.         return ConcatenateTimeSpanParts(result, resultCount, collectionSeparator ?? ", ");
117.     }
118. 
119.     /// <summary>
120.     /// Breaks down a TimeSpan into its component time part strings for each unit
121.     /// between maxUnit and minUnit. Writes into the provided span to avoid allocation.
122.     /// </summary>
123.     private static int CreateTimeParts(
124.         TimeSpan timeSpan, TimeUnit maxUnit, TimeUnit minUnit, Span<string?> timeParts)
125.     {
126.         var totalDays = Math.Abs(timeSpan.TotalDays);
127.         int count = 0;
128. 
129.         foreach (var unit in TimeUnits)
130.         {
131.             if (unit < minUnit || unit > maxUnit)
132.             {
133.                 continue;
134.             }
135. 
136.             var value = unit switch
137.             {
138.                 TimeUnit.Year => (int)(totalDays / DaysInAYear),
139.                 TimeUnit.Month => (int)((totalDays % DaysInAYear) / DaysInAMonth),
140.                 TimeUnit.Week => (int)((totalDays % DaysInAMonth) / DaysInAWeek),
141.                 TimeUnit.Day => (int)(totalDays % DaysInAWeek),
142.                 TimeUnit.Hour => timeSpan.Hours,
143.                 TimeUnit.Minute => timeSpan.Minutes,
144.                 TimeUnit.Second => timeSpan.Seconds,
145.                 TimeUnit.Millisecond => timeSpan.Milliseconds,
146.                 _ => 0
147.             };
148. 
149.             timeParts[count++] = value != 0 ? FormatTimePart(value, unit) : null;
150.         }
151. 
152.         return count;
153.     }
154. 
155.     private static bool IsContainingOnlyNullValue(ReadOnlySpan<string?> timeParts, int count)
156.     {
157.         for (int i = 0; i < count; i++)
158.             if (timeParts[i] != null)
159.                 return false;
160.         return true;
161.     }
162. 
163.     /// <summary>
164.     /// Applies precision filtering directly over the span, avoiding LINQ iterator allocations.
165.     /// </summary>
166.     private static int ApplyPrecision(
167.         ReadOnlySpan<string?> timeParts, int count, int precision, bool countEmptyUnits,
168.         Span<string> result)
169.     {
170.         int resultCount = 0;
171.         int taken = 0;
172. 
173.         for (int i = 0; i < count && taken < precision; i++)
174.         {
175.             if (countEmptyUnits)
176.             {
177.                 taken++;
178.                 if (timeParts[i] != null)
179.                     result[resultCount++] = timeParts[i]!;
180.             }
181.             else
182.             {
