 using System.Globalization;

 namespace Textualizer;

 /// <summary>
 /// Specifies the unit of time for humanization purposes.
 /// Values are ordered from largest to smallest.
 /// </summary>
 public enum TimeUnit
 {
     /// <summary>Years.</summary>
     Year,
     /// <summary>Months.</summary>
     Month,
     /// <summary>Weeks.</summary>
     Week,
     /// <summary>Days.</summary>
     Day,
     /// <summary>Hours.</summary>
     Hour,
     /// <summary>Minutes.</summary>
     Minute,
     /// <summary>Seconds.</summary>
     Second,
     /// <summary>Milliseconds.</summary>
     Millisecond
 }

 /// <summary>
 /// Provides extension methods for converting <see cref="TimeSpan"/> values to
 /// human-readable strings with configurable precision, culture, and unit ranges.
 /// </summary>
 public static class TimeSpanReadabilityExtensions
 {
     private const int DaysInAWeek = 7;
     private const double DaysInAYear = 365.2425;
     private const double DaysInAMonth = DaysInAYear / 12;

     // Reversed literal avoids Enumerable.Reverse + Enum.GetValues allocations at static init.
     private static readonly TimeUnit[] TimeUnits =
     [
         TimeUnit.Millisecond, TimeUnit.Second, TimeUnit.Minute, TimeUnit.Hour,
         TimeUnit.Day, TimeUnit.Week, TimeUnit.Month, TimeUnit.Year
     ];

     // Pre-computed lowercase unit names keyed by enum value, avoiding
     // Enum.ToString() (reflection-based) and ToLowerInvariant() per call.
     private static readonly string[] UnitNamesSingular;
     private static readonly string[] UnitNamesPlural;

     static TimeSpanReadabilityExtensions()
     {
         var values = Enum.GetValues<TimeUnit>();
         var max = 0;
         foreach (var v in values)
             if ((int)v > max)
                 max = (int)v;

         UnitNamesSingular = new string[max + 1];
         UnitNamesPlural = new string[max + 1];
         foreach (var v in values)
         {
             var name = v.ToString().ToLowerInvariant();
             UnitNamesSingular[(int)v] = name;
             UnitNamesPlural[(int)v] = name + "s";
         }
     }

     /// <summary>
     /// Converts a <see cref="TimeSpan"/> to a human-readable string.
     /// </summary>
     /// <param name="timeSpan">The time span to humanize.</param>
     /// <param name="precision">The number of time units to include (e.g., 2 for "1 hour, 30 minutes").</param>
     /// <param name="culture">The culture for localized formatting. Uses current culture if null.</param>
     /// <param name="maxUnit">The largest time unit to display.</param>
     /// <param name="minUnit">The smallest time unit to display.</param>
     /// <param name="collectionSeparator">The separator between time parts (default: ", ").</param>
     /// <param name="countEmptyUnits">Whether empty units count toward precision.</param>
     /// <returns>A human-readable string representation of the time span.</returns>
     /// <example>
     /// <code>
     /// TimeSpan.FromMinutes(90).Humanize() => "1 hour"
     /// TimeSpan.FromMinutes(90).Humanize(precision: 2) => "1 hour, 30 minutes"
     /// TimeSpan.FromDays(1.5).Humanize(precision: 3) => "1 day, 12 hours"
     /// </code>
     /// </example>
     public static string Humanize(
         this TimeSpan timeSpan,
         int precision = 1,
         CultureInfo? culture = null,
         TimeUnit maxUnit = TimeUnit.Year,
         TimeUnit minUnit = TimeUnit.Millisecond,
         string? collectionSeparator = null,
         bool countEmptyUnits = false)
     {
         culture ??= CultureInfo.CurrentCulture;

         // Use a stack-based buffer (max 8 units) to avoid List<> allocation.
         Span<string?> buffer = new string?[TimeUnits.Length];
         int count = CreateTimeParts(timeSpan, maxUnit, minUnit, buffer);

         if (IsContainingOnlyNullValue(buffer, count))
         {
             return "no time";
         }

         // Apply precision and collect non-null parts into a small list.
         Span<string> result = new string[Math.Min(precision, count)];
         int resultCount = ApplyPrecision(buffer, count, precision, countEmptyUnits, result);

         if (resultCount == 0)
         {
             return "no time";
         }

         return ConcatenateTimeSpanParts(result, resultCount, collectionSeparator ?? ", ");
     }

     /// <summary>
     /// Breaks down a TimeSpan into its component time part strings for each unit
     /// between maxUnit and minUnit. Writes into the provided span to avoid allocation.
     /// </summary>
     private static int CreateTimeParts(
         TimeSpan timeSpan, TimeUnit maxUnit, TimeUnit minUnit, Span<string?> timeParts)
     {
         var totalDays = Math.Abs(timeSpan.TotalDays);
         int count = 0;

         foreach (var unit in TimeUnits)
         {
             if (unit < minUnit || unit > maxUnit)
             {
                 continue;
             }

             var value = unit switch
             {
                 TimeUnit.Year => (int)(totalDays / DaysInAYear),
                 TimeUnit.Month => (int)((totalDays % DaysInAYear) / DaysInAMonth),
                 TimeUnit.Week => (int)((totalDays % DaysInAMonth) / DaysInAWeek),
                 TimeUnit.Day => (int)(totalDays % DaysInAWeek),
                 TimeUnit.Hour => timeSpan.Hours,
                 TimeUnit.Minute => timeSpan.Minutes,
                 TimeUnit.Second => timeSpan.Seconds,
                 TimeUnit.Millisecond => timeSpan.Milliseconds,
                 _ => 0
             };

             timeParts[count++] = value != 0 ? FormatTimePart(value, unit) : null;
         }

         return count;
     }

     private static bool IsContainingOnlyNullValue(ReadOnlySpan<string?> timeParts, int count)
     {
         for (int i = 0; i < count; i++)
             if (timeParts[i] != null)
                 return false;
         return true;
     }

     /// <summary>
     /// Applies precision filtering directly over the span, avoiding LINQ iterator allocations.
     /// </summary>
     private static int ApplyPrecision(
         ReadOnlySpan<string?> timeParts, int count, int precision, bool countEmptyUnits,
         Span<string> result)
     {
         int resultCount = 0;
         int taken = 0;

         for (int i = 0; i < count && taken < precision; i++)
         {
             if (countEmptyUnits)
             {
                 taken++;
                 if (timeParts[i] != null)
                     result[resultCount++] = timeParts[i]!;
             }
             else
             {
                 if (timeParts[i] != null)
                 {
                     taken++;
                     result[resultCount++] = timeParts[i]!;
                 }
             }
         }

         return resultCount;
     }

     /// <summary>
     /// Joins time part strings with the specified separator.
     /// </summary>
     private static string ConcatenateTimeSpanParts(
         ReadOnlySpan<string> parts, int count, string collectionSeparator)
     {
         if (count == 1)
         {
             return parts[0];
         }

         var allButLast = string.Join(collectionSeparator, parts[..(count - 1)].ToArray());
         return $"{allButLast} and {parts[count - 1]}";
     }

     private static string FormatTimePart(int value, TimeUnit unit)
     {
         var unitName = value == 1 ? UnitNamesSingular[(int)unit] : UnitNamesPlural[(int)unit];
         return $"{value} {unitName}";
     }
 }

